1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	}
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	};
23	
24	export function quote(input: QuoteInput): number {
25	  const basePremium = input.items.reduce(
26	    (total, item) => total + BASE_PREMIUMS[item.type],
27	    0,
28	  );
29	  return basePremium + PROCESSING_FEE;
30	}
31	
32	export function claim(input: unknown): number {
33	  return undefined as unknown as number;
34	}
